class Solution {
    public int numberOfArrays(String s, int k) {
        int MOD = 1000000007;
        int n = s.length();
        int[] dp = new int[n + 1];
        dp[0] = 1;
        for (int i = 0; i < n; i++) {
            int cur = s.charAt(i) - '0';
            for (int j = Math.max(0, i - 1); j >= 0; j--) {
                if (cur <= k) {
                    dp[i + 1] = (dp[i + 1] + dp[j]) % MOD;
                }
                cur = cur * 10 + (s.charAt(j + 1) - '0');
            }
        }
        return dp[n];
    }
}
